<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">path</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#89B4FA;font-style:italic;"> println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Valid directory: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> path</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">display</span><span style="color:#9399B2;">()),</span></span>
